    -- Only dates from this week: 2026-04-02 to 2026-04-08
    (196,'Simon Willison: Why MCP Changes Everything for AI Tooling',          '0195f300-1001-7000-b000-000000000062', 'THIS_WEEKS_POSTS', '0195f300-2001-7000-a000-000000000081', 'Blog',      'MCP Protocol', '0195f300-0001-7000-a000-000000000005', 5, 88.0, '2026-04-02', NULL, 'Simon Willison argues MCP represents the most important AI infrastructure shift since the transformer, enabling composable AI tool ecosystems.', 'Must-read perspective on why MCP adoption signals a new era of AI-native software architecture.'),
    (197,'r/LangChain: Community Migrates from LCEL to LangGraph Patterns',    '0195f300-1001-7000-b000-000000000010', 'THIS_WEEKS_POSTS', '0195f300-2001-7000-a000-000000000080', 'Community', 'LangChain',    '0195f300-0001-7000-a000-000000000005', 3, 55.0, '2026-04-04', NULL, 'LangChain subreddit thread shows growing community shift from LCEL chains to LangGraph for production agent workflows.', 'Useful community signal on evolving framework adoption patterns within the LangChain ecosystem.'),
    (198,'Andrej Karpathy: The Case for LLM-Native Software Architecture',      '0195f300-1001-7000-b000-000000000001', 'THIS_WEEKS_POSTS', '0195f300-2001-7000-a000-000000000081', 'Blog',      'GPT-5.4',      '0195f300-0001-7000-a000-000000000005', 5, 91.0, '2026-04-05', NULL, 'Karpathy articulates a vision for software architecture redesigned around LLM capabilities rather than bolted on as features.', 'Influential framing for how the next generation of software systems should be designed.'),
    (199,'Hacker News: Self-Hosted vs Cloud LLM: 2026 Cost-Benefit Analysis',  '0195f300-1001-7000-b000-000000000001', 'THIS_WEEKS_POSTS', '0195f300-2001-7000-a000-000000000081', 'Blog',      'GPT-5.4',      '0195f300-0001-7000-a000-000000000005', 4, 72.0, '2026-04-06', NULL, 'Popular HN thread aggregates community data on self-hosted vs cloud LLM economics across different workload scales.', 'Crowdsourced cost analysis that supplements vendor benchmarks with practitioner real-world data.'),
    (200,'AI Engineering Weekly: This Week in Agent Frameworks',                '0195f300-1001-7000-b000-000000000010', 'THIS_WEEKS_POSTS', '0195f300-2001-7000-a000-000000000080', 'Community', 'LangChain',    '0195f300-0001-7000-a000-000000000006', 4, 68.0, '2026-04-08', NULL, 'AI Engineering Weekly roundup covers LangGraph Cloud, CrewAI 0.9, and AutoGPT cost guardrails released this week.', 'Concise weekly summary for practitioners staying current with fast-moving agent framework developments.')
    ) AS t(seq, title, entity_id, page, cat_id, cat_name, entity_name, source_id, score, impact, pub_date, side_cat, summary, why_matters)
)
LOOP
    i := i + 1;

    v_art_id  := ('0195f300-a' || lpad(rec.seq::TEXT, 3, '0') || '-7000-8000-000000000001')::UUID;
    v_uas_id  := ('0195f300-b' || lpad(rec.seq::TEXT, 3, '0') || '-7000-8000-000000000001')::UUID;
    v_aai_id  := ('0195f300-c' || lpad(rec.seq::TEXT, 3, '0') || '-7000-8000-000000000001')::UUID;
    v_pub_at  := (rec.pub_date || 'T08:00:00Z')::TIMESTAMPTZ;
    v_url     := 'https://example.com/article-' || rec.seq;

    -- Build tags JSON
    v_tags := jsonb_build_array(
        jsonb_build_object('kind', 'TAG', 'value', lower(rec.entity_name)),
        jsonb_build_object('kind', 'TAG', 'value', lower(replace(rec.cat_name, ' ', '-'))),
        jsonb_build_object('kind', 'KEYWORD', 'value', lower(rec.page::TEXT), 'frequency', (3 + rec.score), 'confidence', round(0.6 + rec.score * 0.08, 2))
    );

    -- Build key_points and risk_notes
    v_key_points := jsonb_build_array(
        'Key update for ' || rec.entity_name,
        rec.cat_name || ' category development'
    );
    v_risk_notes := jsonb_build_array(
        'Verify claims with independent benchmarks'
    );

    -- user_article_ai_state
    INSERT INTO content.user_article_ai_state (
        id, user_id, user_article_state_id,
        ai_status,
        representative_entity_id, representative_entity_page,
        representative_entity_category_id, representative_entity_category_name,
        representative_entity_name,
        ai_summary, ai_score,
        ai_classification_json, ai_tags_json, ai_snippets_json,
        ai_evidence_json, ai_structured_extraction_json,
        agent_json_raw,
        ai_model_name, ai_processed_at
    ) VALUES (
        v_aai_id,
        v_user_id,
        v_uas_id,
        'SUCCESS',
        rec.entity_id::UUID,
        rec.page::content.entity_page_enum,
        rec.cat_id::UUID,
        rec.cat_name,
        rec.entity_name,
        rec.summary,
        rec.score,
        -- ai_classification_json
        jsonb_build_object(
            'final_path', jsonb_build_object(
                'page', rec.page,
                'category_name', rec.cat_name,
                'entity_name', rec.entity_name
            ),
            'candidates', jsonb_build_array(
                jsonb_build_object(
                    'page', rec.page,
                    'category_name', rec.cat_name,
                    'entity_name', rec.entity_name,
                    'confidence', round(0.80 + rec.score * 0.03, 2)
                )
            ),
            'decision_reason', 'title and source strongly match tracked entity'
        ),
        -- ai_tags_json
        v_tags,
        -- ai_snippets_json
        jsonb_build_object(
            'why_it_matters', rec.why_matters,
            'key_points', v_key_points,
            'risk_notes', v_risk_notes
        ),
        -- ai_evidence_json
        jsonb_build_object(
            'evidence_items', jsonb_build_array(
                jsonb_build_object(
                    'kind', 'quote',
                    'text', left(rec.summary, 80),
                    'url', v_url,
                    'source_name', 'Seed Source',
                    'published_at', v_pub_at
                )
            )
        ),
        -- ai_structured_extraction_json
        jsonb_build_object(
            'source', jsonb_build_object('name', 'Seed Source', 'type', 'RSS'),
            'review', jsonb_build_object('type', 'Announcement', 'reviewer', NULL, 'comment', NULL)
        ),
        -- agent_json_raw
        jsonb_build_object(
            'idempotency_key', 'uas:' || lower(v_uas_id::TEXT),
            'version', '0.3',
            'representative_entity', jsonb_build_object(
                'id', rec.entity_id,
                'page', rec.page,
                'category_id', rec.cat_id,
                'category_name', rec.cat_name,
                'name', rec.entity_name
            ),
            'ai_summary', rec.summary,
            'ai_score', rec.score,
            'ai_classification_json', jsonb_build_object(
                'final_path', jsonb_build_object(
                    'page', rec.page,
                    'category_name', rec.cat_name,
                    'entity_name', rec.entity_name
                ),
                'candidates', jsonb_build_array(
                    jsonb_build_object(
                        'page', rec.page,
                        'category_name', rec.cat_name,
                        'entity_name', rec.entity_name,
                        'confidence', round(0.80 + rec.score * 0.03, 2)
                    )
                ),
                'decision_reason', 'title and source strongly match tracked entity'
            ),
            'ai_tags_json', v_tags,
            'ai_snippets_json', jsonb_build_object(
                'why_it_matters', rec.why_matters,
                'key_points', v_key_points,
                'risk_notes', v_risk_notes
            ),
            'ai_evidence_json', jsonb_build_object(
                'evidence_items', jsonb_build_array(
                    jsonb_build_object(
                        'kind', 'quote',
                        'text', left(rec.summary, 80),
                        'url', v_url,
                        'source_name', 'Seed Source',
                        'published_at', v_pub_at
                    )
                )
            ),
            'ai_structured_extraction_json', jsonb_build_object(
                'source', jsonb_build_object('name', 'Seed Source', 'type', 'RSS'),
                'review', jsonb_build_object('type', 'Announcement', 'reviewer', NULL, 'comment', NULL)
            )
        ),
        'claude-3.7-sonnet',
        v_pub_at + INTERVAL '2 hours'
    );

END LOOP;
RAISE NOTICE 'Step 4 done: % rows inserted.', i;
END $$;
